fn stack_push(stack: i64, size: i64, capacity: i64, x: i64) -> i64
    pre size < capacity
= {
    let _p = vec_push(stack, x);
    size + 1
};

fn stack_pop(stack: i64, size: i64) -> i64
    pre size > 0
= {
    let top = vec_get(stack, size - 1);
    let _p = vec_pop(stack);
    top
};

fn main() -> i64 = {
    let capacity = read_int();
    let q = read_int();
    let stack = vec_new();
    let mut size = 0;

    for _i in 0..q {
        let op = read_int();
        if op == 1 {
            let x = read_int();
            if size < capacity {
                size = stack_push(stack, size, capacity, x)
            } else {
                let _p = println_str("FULL");
                ()
            }
        } else if op == 2 {
            if size > 0 {
                let val = stack_pop(stack, size);
                size = size - 1;
                let _p = println(val);
                ()
            } else {
                let _p = println_str("EMPTY");
                ()
            }
        } else {
            let _p = println(size);
            ()
        }
    };

    0
};
